void UTestbed1StructInterfaceMQTTClient::onSigBool(const IApiGearMqttClient::FReceivedMessage& InMsg)
{
	const std::string Payload(reinterpret_cast<const char*>(InMsg.Payload.GetData()), InMsg.Payload.Num());
	nlohmann::json json_args = nlohmann::json::parse(Payload);

	// check for correct array size
	if (!json_args.is_array() || json_args.size() < 1)
	{
		UE_LOG(LogTestbed1StructInterfaceMQTTClient, Error, TEXT("Signal sigBool: invalid args array (expected 1 elements)"));
		return;
	}

	// make sure the type matches our expectation
	if (json_args[0].is_null() || !json_args[0].is_object())
	{
		UE_LOG(LogTestbed1StructInterfaceMQTTClient, Error, TEXT("Signal paramBool: invalid type for parameter 0"));
		return;
	}
	const FTestbed1StructBool& outParamBool = json_args[0].get<FTestbed1StructBool>();

	TWeakObjectPtr<UTestbed1StructInterfaceMQTTClient> weak(this);
	AsyncTask(ENamedThreads::GameThread, [weak, outParamBool]()
		{
		if (auto* self = weak.Get())
		{
			self->_GetPublisher()->BroadcastSigBoolSignal(outParamBool);
		}
	});
}

